import java.nio.file.Files;
import java.nio.file.Path;
import java.nio.file.Paths;
import java.io.IOException;

public class PathTraversalSecureCode {

    public static void main(String[] args) {
        String userInput = "../../../../../etc/passwd";
        String basePath = "/path/to/files/";

        try {
            Path resolvedPath = Paths.get(basePath).resolve(userInput).normalize();

            if (!resolvedPath.startsWith(Paths.get(basePath))) {
                throw new SecurityException("Invalid file path");
            }

            byte[] fileContent = Files.readAllBytes(resolvedPath);
            System.out.println(new String(fileContent));
        } catch (IOException | SecurityException e) {
            e.printStackTrace();
        }
    }
}

